    const b3 = c3.charCodeAt(0);
    return Buffer.from([b1, b2, b3]).toString('utf8');
  });

  // Fix 2-byte double-encoded UTF-8 sequences
  fixed = fixed.replace(/([\u00c2-\u00df])([\u0080-\u00bf])/g, (match, c1, c2) => {
    const b1 = c1.charCodeAt(0);
    const b2 = c2.charCodeAt(0);
    return Buffer.from([b1, b2]).toString('utf8');
  });

  return fixed;
}

function processDirectory(dir) {
  const items = fs.readdirSync(dir);
  for (const item of items) {
    const fullPath = path.join(dir, item);
    const stat = fs.statSync(fullPath);
    if (stat.isDirectory()) {
      processDirectory(fullPath);
    } else if (stat.isFile() && (item.endsWith('.ts') || item.endsWith('.tsx'))) {
      let content = fs.readFileSync(fullPath, 'utf8');

      // Perform general encoding fix
      let fixedContent = fixEncoding(content);

      // Also replace Spanish "licencias" / "Licencias" with "licencas" / "Licencas"
      // (For file imports and tab keys)
      fixedContent = fixedContent.replace(/licencias/g, 'licencas');
      fixedContent = fixedContent.replace(/LicenciasTab/g, 'LicencasTab');

      if (content !== fixedContent) {
        console.log(`Corrigindo codificação e referências em: ${fullPath}`);
        fs.writeFileSync(fullPath, fixedContent, 'utf8');
      }
    }
  }
}

// 1. Process all files in src/ to fix double-encoding and change references of "licencias" to "licencas"
console.log('Iniciando processamento dos arquivos...');
processDirectory(srcDir);

// 2. Rename the file LicenciasTab.tsx to LicencasTab.tsx if it exists
const oldFilePath = path.join(srcDir, 'components', 'tabs', 'LicenciasTab.tsx');
const newFilePath = path.join(srcDir, 'components', 'tabs', 'LicencasTab.tsx');

if (fs.existsSync(oldFilePath)) {
  console.log(`Renomeando ${oldFilePath} para ${newFilePath}`);
  fs.renameSync(oldFilePath, newFilePath);
}

